import { LitElement, html, css } from "lit";
import { customElement, property, state } from "lit/decorators.js";

export type SnackbarType = "default" | "success" | "error" | "warning" | "info";

@customElement("app-snackbar")
export class AppSnackbar extends LitElement {
  @property() message = "";
  @property() action = "";
  @property({ type: Number }) duration = 4000;
  @property() type: SnackbarType = "default";
  @property({ type: Boolean }) open = false;
  @state() private dismissed = false;
  private timer: number | null = null;

  static override styles = css`
    :host {
      position: fixed;
      bottom: 1.5rem;
      left: 50%;
      transform: translateX(-50%);
      z-index: 9999;
      display: block;
    }
    .bar {
      display: inline-flex;
      align-items: center;
      gap: 0.75rem;
      padding: 0.75rem 1rem;
      border-radius: 0.5rem;
      background: var(--bg-elevated, #1f2937);
      color: var(--text-on-accent, #ffffff);
      font-size: 0.875rem;
      box-shadow: 0 10px 25px rgba(0, 0, 0, 0.2);
      min-width: 280px;
      max-width: 560px;
      border-left: 4px solid var(--accent, #3b82f6);
    }
    .bar.success { border-left-color: var(--success, #10b981); }
    .bar.error { border-left-color: var(--error, #ef4444); }
    .bar.warning { border-left-color: var(--warning, #f59e0b); }
    .bar.info { border-left-color: var(--info, #3b82f6); }
    .message { flex: 1; }
    .action-btn {
      background: transparent;
      border: none;
      color: var(--accent, #3b82f6);
      font-weight: 600;
      cursor: pointer;
      padding: 0.25rem 0.5rem;
      border-radius: 0.25rem;
      text-transform: uppercase;
      font-size: 0.75rem;
    }
    .action-btn:hover { background: rgba(255, 255, 255, 0.1); }
    .close-btn {
      background: transparent;
      border: none;
      color: inherit;
      cursor: pointer;
      padding: 0.125rem 0.25rem;
      opacity: 0.7;
      font-size: 1.125rem;
      line-height: 1;
    }
    .close-btn:hover { opacity: 1; }
  `;

  override updated(changed: Map<string, unknown>): void {
    if (changed.has("open") && this.open && !this.dismissed) {
      if (this.timer !== null) clearTimeout(this.timer);
      this.timer = window.setTimeout(() => this.dismiss(), this.duration);
    }
  }

  override disconnectedCallback(): void {
    super.disconnectedCallback();
    if (this.timer !== null) clearTimeout(this.timer);
  }

  private dismiss = () => {
    this.dismissed = true;
    this.open = false;
    this.dispatchEvent(new CustomEvent("dismiss", { bubbles: true, composed: true }));
  };

  private handleAction = () => {
    this.dispatchEvent(new CustomEvent("action", { bubbles: true, composed: true }));
    this.dismiss();
  };

  override render() {
    if (!this.open) return html``;
    return html`
      <div class="bar ${this.type}" role="status">
        <span class="message">${this.message}</span>
        ${this.action ? html`<button class="action-btn" @click=${this.handleAction}>${this.action}</button>` : ""}
        <button class="close-btn" @click=${this.dismiss} aria-label="Dismiss">×</button>
      </div>
    `;
  }
}
