import { LitElement, html, css } from "lit";
import { customElement, property } from "lit/decorators.js";

export interface LanguageOption {
  code: string;
  name: string;
}

@customElement("app-language-selector")
export class AppLanguageSelector extends LitElement {
  @property() languages = "";
  @property() value = "";
  @property() label = "";
  @property() labelId = "";

  static override styles = css`
    :host {
      display: inline-flex;
      flex-direction: column;
      gap: 0.25rem;
    }

    .selector-label {
      font-size: 0.875rem;
      font-weight: 500;
      color: var(--text-primary);
    }

    .select-wrapper {
      position: relative;
      display: inline-flex;
      align-items: center;
    }

    select {
      appearance: none;
      -webkit-appearance: none;
      padding: 0.5rem 2rem 0.5rem 0.75rem;
      border-radius: 0.5rem;
      border: 1px solid var(--border-color);
      background-color: var(--bg-elevated);
      color: var(--text-primary);
      font-size: 0.875rem;
      font-family: inherit;
      cursor: pointer;
      outline: none;
      transition: border-color 0.15s;
    }

    select:focus {
      border-color: var(--accent);
      box-shadow: 0 0 0 1px var(--accent);
    }

    .chevron-icon {
      position: absolute;
      right: 0.5rem;
      pointer-events: none;
      width: 1rem;
      height: 1rem;
      color: var(--text-muted);
    }
  `;

  private _handleChange(e: Event) {
    const select = e.target as HTMLSelectElement;
    this.value = select.value;
    this.dispatchEvent(
      new CustomEvent("change", {
        detail: { value: select.value },
        bubbles: true,
        composed: true,
      }),
    );
  }

  private _getParsedLanguages(): LanguageOption[] {
    try {
      if (typeof this.languages === "string") {
        return JSON.parse(this.languages || "[]");
      }
      if (Array.isArray(this.languages)) {
        return this.languages as LanguageOption[];
      }
      return [];
    } catch {
      return [];
    }
  }

  override render() {
    const langs = this._getParsedLanguages();
    return html`
      ${this.label
        ? html`<span class="selector-label" id="${this.labelId || ""}">${this.label}</span>`
        : ""}
      <div class="select-wrapper">
        <select
          .value="${this.value || ""}"
          aria-labelledby="${this.labelId || ""}"
          @change="${this._handleChange}"
        >
          ${langs.map(
            (lang) => html`<option value="${lang.code}">${lang.name}</option>`,
          )}
        </select>
        <svg class="chevron-icon" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
          <polyline points="6 9 12 15 18 9"></polyline>
        </svg>
      </div>
    `;
  }
}

declare global {
  interface HTMLElementTagNameMap {
    "app-language-selector": AppLanguageSelector;
  }
}
