import { LitElement, html, css } from "lit";
import { customElement, property } from "lit/decorators.js";

@customElement("app-nav-item")
export class AppNavItem extends LitElement {
  @property() label = "";
  @property() icon: string | null = null;
  @property({ type: Boolean }) active = false;
  @property({ type: Boolean }) disabled = false;

  static override styles = css`
    :host {
      display: block;
    }

    button {
      display: flex;
      align-items: center;
      gap: 0.5rem;
      width: 100%;
      padding: 0.5rem 0.75rem;
      border: none;
      border-radius: 0.375rem;
      background: transparent;
      color: var(--text-primary);
      font-size: 0.875rem;
      font-weight: 500;
      text-align: left;
      cursor: pointer;
      transition: background-color 0.15s, color 0.15s;
    }

    button:hover:not(:disabled) {
      background-color: var(--bg-hover);
      color: var(--text-primary);
    }

    button:disabled {
      opacity: 0.5;
      cursor: not-allowed;
    }

    button.active {
      background: var(--accent);
      color: var(--text-on-accent);
    }

    button.active:hover {
      background: var(--accent-hover);
    }

    .nav-icon {
      display: flex;
      align-items: center;
      justify-content: center;
      width: 1.25rem;
      height: 1.25rem;
      font-size: 1.25rem;
      flex-shrink: 0;
    }

    .nav-label {
      white-space: nowrap;
      overflow: hidden;
      text-overflow: ellipsis;
    }
  `;

  private _handleClick(e: MouseEvent) {
    if (this.disabled) {
      e.preventDefault();
      e.stopPropagation();
      return;
    }
    this.dispatchEvent(
      new CustomEvent("click", { detail: e, bubbles: true, composed: true }),
    );
  }

  override render() {
    return html`
      <button
        type="button"
        class="${this.active ? "active" : ""}"
        ?disabled="${this.disabled}"
        @click="${this._handleClick}"
      >
        ${this.icon
          ? html`<i class="material-icons nav-icon">${this.icon}</i>`
          : ""}
        <span class="nav-label">${this.label}</span>
      </button>
    `;
  }
}

declare global {
  interface HTMLElementTagNameMap {
    "app-nav-item": AppNavItem;
  }
}
